const item = $input.item.json;
const headers = item.payload?.headers || [];
const getHeader = (nombre) => (headers.find(h => (h.name || '').toLowerCase() === nombre.toLowerCase()) || {}).value || '';

const asunto = getHeader('Subject');
const remitenteCrudo = getHeader('From');

const match = asunto.match(/TK-\d{6}/);
if (!match) {
  return []; // no es una respuesta a un ticket — se ignora, sin error
}

// "Nombre Apellido <correo@dominio.com>" -> solo el correo
const emailMatch = remitenteCrudo.match(/<(.+)>/);
const remitenteEmail = (emailMatch ? emailMatch[1] : remitenteCrudo).trim().toLowerCase();

// Nunca procesar correos que vienen de la propia casilla del sistema
if (remitenteEmail === 'tramites@yavirac.edu.ec') {
  return [];
}

return [{ json: { ticketCodigo: match[0], remitenteEmail, gmailMessageId: item.id } }];

const correos = ($json.correos || '').split(',').map(c => c.trim());
const remitente = $('Extraer Código y Remitente').item.json.remitenteEmail;
const autorizado = correos.includes(remitente);
return [{ json: { autorizado } }];

const ticket = $json;
const remitente = $('Extraer Código y Remitente').item.json.remitenteEmail;
const payload = JSON.stringify({
  ticket_id: String(ticket.id),
  codigo: ticket.codigo,
  resuelto_por: remitente
});
return [{ json: { payload } }];
